import * as core from '@actions/core';
import * as github from '@actions/github';
import { GitHub, getOctokitOptions } from '@actions/github/lib/utils';
import { throttling } from '@octokit/plugin-throttling';
import * as path from 'path';

import config from './config.js';
import { dedent, execGit, execGitBuffer, remove } from './helpers.js';

import type { RepoInfo, TreeDiffEntry, GitDiffDict } from './types.js';

// Pull request type from GitHub API (simplified for our use case)
interface PullRequestInfo {
  number: number;
  html_url: string;
  body: string | null;
}

// The concrete action taken on the pull request, so callers can report exactly
// what happened instead of a generic "created/updated".
type PrAction = 'created' | 'updated' | 'reopened';

const BLOB_UPLOAD_CONCURRENCY = 4;

interface PullRequestResult extends PullRequestInfo {
  action: PrAction;
}

// Git tree entry type for GitHub API
type GitTreeMode = '100644' | '100755' | '040000' | '160000' | '120000';

interface GitHubTreeEntry {
  path?: string;
  mode?: GitTreeMode;
  type?: 'blob' | 'tree' | 'commit';
  sha?: string | null;
  content?: string;
}

const {
  GITHUB_TOKEN,
  GITHUB_SERVER_URL,
  IS_INSTALLATION_TOKEN,
  IS_FINE_GRAINED,
  GIT_USERNAME,
  GIT_EMAIL,
  TMP_DIR,
  COMMIT_BODY,
  COMMIT_PREFIX,
  GITHUB_REPOSITORY,
  OVERWRITE_EXISTING_PR,
  SKIP_PR,
  PR_BODY,
  BRANCH_PREFIX,
  FORK,
  REBASE
} = config;

export default class Git {
  private github: InstanceType<typeof GitHub>['rest'];
  private repo!: RepoInfo;
  private existingPr: PullRequestInfo | undefined;
  private prBranch: string | undefined;
  private prBranchSuffix: string | undefined;
  private baseBranch!: string;
  private gitUrl!: string;
  private lastCommitSha!: string;
  private lastCommitChanges: GitDiffDict | undefined;
  private remoteBranchHead: string | undefined;
  private forceUpdateBranch = false;
  private reopenClosedPr = false;
  private prWasReopened = false;
  public isEmptyRepo = false;
  public workingDir!: string;

  constructor() {
    // Cast throttling to handle version mismatch between @actions/github and @octokit/plugin-throttling
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const Octokit = GitHub.plugin(throttling as any);

    const options = getOctokitOptions(GITHUB_TOKEN, {
      baseUrl: process.env['GITHUB_API_URL'] || 'https://api.github.com',
      throttle: {
        onRateLimit: (retryAfter: number) => {
          core.debug(`Hit GitHub API rate limit, retrying after ${retryAfter}s`);
          return true;
        },
        onSecondaryRateLimit: (retryAfter: number) => {
          core.debug(`Hit secondary GitHub API rate limit, retrying after ${retryAfter}s`);
          return true;
        }
      }
    });

    const octokit = new Octokit(options);
    this.github = octokit.rest;
  }

  private static literalPathspec(file: string): string {
    return `:(literal)${file.replace(/\\/g, '/')}`;
  }

  private branchRemote(): 'origin' | 'fork' {
    return FORK ? 'fork' : 'origin';
  }

  private forceWithLeaseArg(branch: string): string {
    return this.remoteBranchHead ?
        `--force-with-lease=refs/heads/${branch}:${this.remoteBranchHead}`
      : '--force-with-lease';
  }

  private static toSafePathSegment(input: string): string {
    const trimmed = input.trim();
    if (!trimmed) return 'default';
    // Avoid path traversal and Windows-invalid characters while keeping it readable.
    // Intentionally avoid control-character regex ranges here to satisfy eslint no-control-regex.
    const sanitized = Array.from(trimmed, (ch) => {
      const code = ch.codePointAt(0)!;
      if (code < 0x20) return '_';
      if ('\\/<>:"|?*'.includes(ch)) return '_';
      return ch;
    }).join('');

    const compact = sanitized.replace(/\.+/g, '.').replace(/[. ]+$/g, '');
    return compact && compact !== '.' && compact !== '..' ? compact : 'default';
  }

  async initRepo(repo: RepoInfo, branchSuffix = ''): Promise<void> {
    // Reset repo specific values
    this.existingPr = undefined;
    this.prBranch = undefined;
    this.prBranchSuffix = undefined;
    this.remoteBranchHead = undefined;
    this.forceUpdateBranch = false;
    this.reopenClosedPr = false;
    this.prWasReopened = false;
    this.lastCommitChanges = undefined;
    this.isEmptyRepo = false;

    // Set values to current repo
    this.repo = repo;
    const suffixDir = Git.toSafePathSegment(branchSuffix);
    this.workingDir = path.join(
      TMP_DIR,
      Git.toSafePathSegment(repo.host),
      Git.toSafePathSegment(repo.user),
      Git.toSafePathSegment(`${repo.name}@${repo.branch}`),
      suffixDir
    );
    this.gitUrl = `https://${IS_INSTALLATION_TOKEN ? 'x-access-token:' : ''}${
      IS_FINE_GRAINED ? 'oauth:' : ''
    }${GITHUB_TOKEN}@${repo.fullName}.git`;

    await this.clone();
    await this.setIdentity();

    // A freshly created target repo can have a default branch with no commits
    // (unborn HEAD). The rev-parse calls below would otherwise fail with
    // "ambiguous argument 'HEAD'" and abort the entire run, so detect it here
    // and let the caller skip the repo instead.
    this.isEmptyRepo = await this.hasNoCommits();
    if (this.isEmptyRepo) {
      core.warning(`${repo.fullName} has no commits on the default branch - skipping`);
      return;
    }

    await this.getBaseBranch();
    await this.getLastCommitSha();

    if (FORK) {
      const forkUrl = new URL(GITHUB_SERVER_URL);
      forkUrl.username = GITHUB_TOKEN;
      forkUrl.pathname = `${FORK}/${this.repo.name}.git`;
      await this.createFork();
      await this.createRemote(forkUrl.toString());
    }
  }

  async createFork(): Promise<void> {
    core.debug(`Creating fork with OWNER: ${this.repo.user} and REPO: ${this.repo.name}`);
    await this.github.repos.createFork({
      owner: this.repo.user,
      repo: this.repo.name
    });
  }

  async createRemote(forkUrl: string): Promise<string> {
    return execGit(['remote', 'add', 'fork', forkUrl], this.workingDir);
  }

  async clone(): Promise<string> {
    core.debug(`Cloning ${this.repo.fullName} into ${this.workingDir}`);

    const branchArgs = this.repo.branch !== 'default' ? ['--branch', this.repo.branch] : [];

    return execGit(['clone', '--depth', '1', ...branchArgs, this.gitUrl, this.workingDir]);
  }

  async setIdentity(): Promise<string> {
    let username = GIT_USERNAME;
    let email = GIT_EMAIL;

    if (email === undefined) {
      if (!IS_INSTALLATION_TOKEN) {
        const { data } = await this.github.users.getAuthenticated();
        email = data.email ?? undefined;
        username = data.login;
      }
    }

    core.debug(`Setting git user to email: ${email}, username: ${username}`);

    await execGit(['config', '--local', 'user.name', String(username)], this.workingDir);
    return execGit(['config', '--local', 'user.email', String(email)], this.workingDir);
  }

  async getBaseBranch(): Promise<void> {
    this.baseBranch = await execGit(['rev-parse', '--abbrev-ref', 'HEAD'], this.workingDir);
  }

  async createPrBranch(branchSuffix = ''): Promise<void> {
    this.prBranchSuffix = branchSuffix;
    const repoName = GITHUB_REPOSITORY.split('/')[1] ?? '';
    const prefix = BRANCH_PREFIX.replace('SOURCE_REPO_NAME', repoName);

    let newBranch = path.join(prefix, this.repo.branch).replace(/\\/g, '/').replace(/\/\./g, '/');
    newBranch += branchSuffix ? `-${branchSuffix}` : '';

    this.prBranch = newBranch;

    if (OVERWRITE_EXISTING_PR === false) {
      newBranch += `-${Math.round(new Date().getTime() / 1000)}`;
      this.prBranch = newBranch;

      core.debug(`Creating PR Branch ${newBranch}`);

      await execGit(['switch', '-c', newBranch], this.workingDir);
      return;
    }

    core.debug(`Switch/Create PR Branch ${newBranch}`);

    const branchRemote = this.branchRemote();

    // Fetch all branches.
    // Use execGit (no shell) so the `*` refspec isn't mangled by cmd.exe on Windows
    // runners, where single quotes are not stripped.
    await execGit(['remote', 'set-branches', branchRemote, '*'], this.workingDir);
    const fetchArgs = branchRemote === 'origin' ? ['fetch', '-v', '--depth=1'] : ['fetch', '-v', '--depth=1', branchRemote];
    await execGit(fetchArgs, this.workingDir);

    try {
      this.remoteBranchHead = await execGit(['rev-parse', '--verify', `${branchRemote}/${newBranch}`], this.workingDir);
    } catch {
      core.debug(`No existing remote branch for ${newBranch}`);
      this.remoteBranchHead = undefined;
    }

    // Inspect the PR state for this branch. A long-lived sync branch (e.g.
    // `repo-sync/default`) accumulates many closed PRs from previous syncs, so a
    // closed PR almost always exists. Only treat the branch as "closed" when
    // there is NO currently-open PR; otherwise the open PR must be reused/rebased.
    // Checking the open PR first prevents the closed-PR path from deleting or
    // rewriting the branch of a live PR (deleting the branch auto-closes the open
    // PR, which is why a rebase-enabled run could end up closing the PR instead).
    const openPr = this.remoteBranchHead ? await this.findExistingPr() : undefined;
    const closedPr = this.remoteBranchHead && !openPr ? await this.getClosedPr() : undefined;

    if (closedPr) {
      // The previous sync PR was closed and no PR is currently open. Rebuild the
      // branch from the base tip and reopen that PR instead of deleting the
      // branch (which orphaned it) or creating a duplicate.
      core.info(`Found closed PR #${closedPr.number} for branch ${newBranch} and no open PR, rebuilding the branch and reopening the PR`);
      this.existingPr = closedPr;
      this.reopenClosedPr = true;

      // Rebuild the PR branch from the base tip; push() force-updates it so the
      // reopened PR always reflects a fresh sync on top of the latest base.
      await execGit(['switch', '-C', newBranch], this.workingDir);
      this.forceUpdateBranch = true;
    } else if (REBASE && this.remoteBranchHead && (await this.isBranchBehindBase(newBranch))) {
      // REBASE: keep an existing sync PR up to date with the base branch
      // (Dependabot-style). The working tree is a fresh clone of the base branch
      // tip, so (re)create the PR branch from that tip and re-apply the sync on
      // top. The branch is then force-updated (see push()), so the same PR is
      // reused but always rebased onto the latest base.
      core.info(`PR branch ${newBranch} is behind ${this.baseBranch}, rebasing onto the latest base`);
      await execGit(['switch', '-C', newBranch], this.workingDir);
      this.forceUpdateBranch = true;
    } else if (this.remoteBranchHead) {
      await execGit(['switch', '--track', '-c', newBranch, `${branchRemote}/${newBranch}`], this.workingDir);
    } else {
      await execGit(['switch', '-c', newBranch], this.workingDir);
    }

    await this.getLastCommitSha();
  }

  async add(file: string): Promise<string> {
    return execGit(['add', '-f', '--', Git.literalPathspec(file)], this.workingDir);
  }

  async remove(file: string): Promise<string> {
    return execGit(['rm', '-r', '-f', '--', Git.literalPathspec(file)], this.workingDir);
  }

  async cleanupRepo(repo: RepoInfo, removeWorkingDir = true): Promise<void> {
    core.debug(`Cleaning up repo ${repo.fullName}`);

    // Remove the working directory
    if (removeWorkingDir && this.workingDir) {
      await remove(this.workingDir);
    }

    // Reset repo-specific values
    this.existingPr = undefined;
    this.prBranch = undefined;
    this.lastCommitChanges = undefined;
    this.reopenClosedPr = false;
    this.prWasReopened = false;
    this.forceUpdateBranch = false;
  }

  isOneCommitPush(): boolean {
    const commits = github.context.payload['commits'] as unknown[] | undefined;
    return github.context.eventName === 'push' && commits?.length === 1;
  }

  originalCommitMessage(): string {
    const commits = github.context.payload['commits'] as Array<{ message?: string }> | undefined;
    return commits?.[0]?.message ?? '';
  }

  /**
   * Parses git diff output and returns a dictionary mapping file paths to their diffs
   */
  parseGitDiffOutput(diffString: string): GitDiffDict {
    // Split diff into separate entries for separate files
    return `\n${diffString}`
      .split('\ndiff --git')
      .slice(1)
      .reduce((resultDict: GitDiffDict, fileDiff) => {
        const lines = fileDiff.split('\n');
        const lastHeaderLineIndex = lines.findIndex((line) => line.startsWith('+++'));

        if (lastHeaderLineIndex === -1) {
          return resultDict; // ignore binary files
        }

        const plainDiff = lines
          .slice(lastHeaderLineIndex + 1)
          .join('\n')
          .trim();

        let filePath = '';
        const headerLine = lines[lastHeaderLineIndex];
        const prevHeaderLine = lines[lastHeaderLineIndex - 1];

        if (headerLine?.startsWith('+++ b/')) {
          // Every file except removed files
          filePath = headerLine.slice(6); // remove '+++ b/'
        } else if (prevHeaderLine) {
          // For removed files, use header line with filename before deletion
          filePath = prevHeaderLine.slice(6); // remove '--- a/'
        }

        return { ...resultDict, [filePath]: plainDiff };
      }, {});
  }

  /**
   * Gets array of git diffs for the source, which can be a file or directory
   */
  async getChangesFromLastCommit(source: string): Promise<string[]> {
    if (this.lastCommitChanges === undefined) {
      const diff = await this.github.repos.compareCommits({
        mediaType: {
          format: 'diff'
        },
        owner: github.context.payload.repository?.owner?.name ?? '',
        repo: github.context.payload.repository?.name ?? '',
        base: github.context.payload['before'] as string,
        head: github.context.payload['after'] as string
      });

      this.lastCommitChanges = this.parseGitDiffOutput(diff.data as unknown as string);
    }

    if (source.endsWith('/')) {
      return Object.keys(this.lastCommitChanges)
        .filter((filePath) => filePath.startsWith(source))
        .map((key) => this.lastCommitChanges![key]!)
        .filter((diff) => diff !== '');
    }

    const change = this.lastCommitChanges[source];
    return change !== undefined ? [change] : [];
  }

  async getLastCommitSha(): Promise<void> {
    this.lastCommitSha = await execGit(['rev-parse', 'HEAD'], this.workingDir);
  }

  /**
   * Detects an empty repository (default branch with no commits / unborn HEAD).
   * `git rev-list -n 1 --all` exits 0 in both cases, printing the newest commit
   * sha or nothing when the repository has no commits yet.
   */
  private async hasNoCommits(): Promise<boolean> {
    const output = await execGit(['rev-list', '-n', '1', '--all'], this.workingDir);
    return output.trim().length === 0;
  }

  /**
   * Gets array of git diffs for the destination, which can be a file or directory
   */
  async changes(destination: string): Promise<string[]> {
    const output = await execGit(['diff', 'HEAD', '--', Git.literalPathspec(destination)], this.workingDir);
    return Object.values(this.parseGitDiffOutput(output));
  }

  async hasChanges(): Promise<boolean> {
    const statusOutput = await execGit(['status', '--porcelain'], this.workingDir);
    // Non-empty output means there are changes
    return statusOutput.trim().length > 0;
  }

  async hasStagedChanges(): Promise<boolean> {
    const output = await execGit(['diff', '--cached', '--name-only'], this.workingDir);
    return output.trim().length > 0;
  }

  async commit(msg?: string): Promise<string> {
    let message = msg ?? `${COMMIT_PREFIX} synced file(s) with ${GITHUB_REPOSITORY}`;

    if (COMMIT_BODY) {
      message += `\n\n${COMMIT_BODY}`;
    }

    return execGit(['commit', '-m', message], this.workingDir);
  }

  /**
   * Returns a git tree parsed for the specified commit sha
   */
  async getTreeId(commitSha: string): Promise<string> {
    core.debug(`Getting treeId for commit ${commitSha}`);

    const output = (await execGit(['cat-file', '-p', commitSha], this.workingDir)).split('\n');

    const commitHeaders = output.slice(
      0,
      output.findIndex((e) => e === '')
    );
    const tree = commitHeaders.find((e) => e.startsWith('tree'))?.replace('tree ', '');

    return tree ?? '';
  }

  async getTreeDiff(referenceTreeId: string, differenceTreeId: string): Promise<TreeDiffEntry[]> {
    const output = await execGit(
      ['diff-tree', '-r', '-z', '--no-commit-id', referenceTreeId, differenceTreeId],
      this.workingDir,
      false
    );
    const fields = output.split('\0');
    const entries: TreeDiffEntry[] = [];

    for (let index = 0; index + 1 < fields.length; index += 2) {
      const metadata = fields[index];
      const filePath = fields[index + 1];

      if (!metadata || filePath === undefined) {
        continue;
      }

      const [newMode = '', previousMode = '', newBlob = '', previousBlob = '', change = ''] = metadata
        .replace(/^:/, '')
        .split(' ');

      entries.push({ newMode, previousMode, newBlob, previousBlob, change, path: filePath });
    }

    return entries;
  }

  /**
   * Creates the blob objects in GitHub for files not in the previous commit
   */
  async uploadGitHubBlob(blob: string): Promise<void> {
    core.debug(`Uploading GitHub Blob for blob ${blob}`);

    const fileContent = await execGitBuffer(['cat-file', '-p', blob], this.workingDir);

    await this.github.git.createBlob({
      owner: this.repo.user,
      repo: this.repo.name,
      content: fileContent.toString('base64'),
      encoding: 'base64'
    });
  }

  /**
   * Gets the commit list in chronological order.
   * Uses lastCommitSha as the base so only locally-made commits are returned.
   * This avoids failures in shallow clones where parent objects of older
   * commits on an existing PR branch are not available.
   */
  async getCommitsToPush(): Promise<string[]> {
    const output = await execGit(['log', '--format=%H', '--reverse', `${this.lastCommitSha}..HEAD`], this.workingDir);
    return output.split('\n').filter(Boolean);
  }

  async getCommitMessage(commitSha: string): Promise<string> {
    return execGit(['log', '-1', '--format=%B', commitSha], this.workingDir);
  }

  /**
   * Runs the complete flow to generate pending commits using the GitHub API
   */
  async createGithubVerifiedCommits(): Promise<void> {
    core.debug('Creating Commits using GitHub API');

    const commits = await this.getCommitsToPush();

    if (!SKIP_PR) {
      // Creates the PR branch if it doesn't exist
      try {
        await this.github.git.createRef({
          owner: this.repo.user,
          repo: this.repo.name,
          sha: this.lastCommitSha,
          ref: 'refs/heads/' + this.prBranch
        });

        core.debug(`Created new branch ${this.prBranch}`);
      } catch (error) {
        const err = error as Error;
        if (!err.message.includes('Reference already exists')) {
          throw error;
        }
      }
    }

    for (const commit of commits) {
      await this.createGithubCommit(commit);
    }

    const targetRef = SKIP_PR ? this.baseBranch : this.prBranch;
    core.debug(`Updating branch ${targetRef} ref`);

    await this.github.git.updateRef({
      owner: this.repo.user,
      repo: this.repo.name,
      ref: `heads/${targetRef}`,
      sha: this.lastCommitSha,
      force: this.forceUpdateBranch
    });

    core.debug('Commit using GitHub API completed');
  }

  async status(): Promise<string> {
    return execGit(['status'], this.workingDir);
  }

  /**
   * Reopen a closed sync PR before its branch is force-pushed/recreated.
   *
   * GitHub refuses to change a closed PR back to "open" once its head branch has
   * been force-pushed or recreated ("state cannot be changed. The <branch>
   * branch was force-pushed or recreated."). The closed-PR flow rebuilds and
   * force-updates the branch, so the reopen must happen first, while the branch
   * still matches the closed PR. If GitHub still refuses (e.g. the branch was
   * already recreated in a previous run), drop the reference so a brand-new PR
   * is created after the push instead.
   */
  private async maybeReopenClosedPr(): Promise<void> {
    if (!this.reopenClosedPr || !this.existingPr) {
      return;
    }

    this.reopenClosedPr = false;
    const prNumber = this.existingPr.number;

    try {
      const { data } = await this.github.pulls.update({
        owner: this.repo.user,
        repo: this.repo.name,
        pull_number: prNumber,
        state: 'open'
      });

      this.existingPr = {
        number: data.number,
        html_url: data.html_url,
        body: data.body
      };
      this.prWasReopened = true;
      core.info(`Reopened PR #${prNumber} before updating its branch`);
    } catch (error) {
      // Expected when the branch was force-pushed/recreated since the PR closed;
      // a fresh PR will be opened on the (re)pushed branch instead.
      core.info(`PR #${prNumber} can't be reopened (${(error as Error).message}); a new PR will be created instead`);
      this.existingPr = undefined;
    }
  }

  async push(): Promise<string | void> {
    const targetBranch = SKIP_PR ? this.baseBranch : this.prBranch;

    if (targetBranch) {
      let currentRemoteHead: string | undefined;
      const branchRemote = this.branchRemote();

      try {
        await execGit(['fetch', branchRemote, targetBranch], this.workingDir);
        currentRemoteHead = await execGit(['rev-parse', '--verify', `${branchRemote}/${targetBranch}`], this.workingDir);
      } catch (error) {
        core.debug(`Remote branch check skipped: ${String(error)}`);
      }

      if (this.remoteBranchHead && currentRemoteHead && currentRemoteHead !== this.remoteBranchHead) {
        throw new Error(`Remote branch ${targetBranch} changed since checkout; refusing to overwrite manual changes.`);
      }
    }

    // Reopen a closed PR *before* its branch is force-pushed/recreated below.
    // GitHub rejects changing a closed PR back to "open" once the head branch
    // has been force-pushed or recreated, so this must happen first.
    await this.maybeReopenClosedPr();

    if (FORK) {
      const forceArgs = this.forceUpdateBranch && this.prBranch ? [this.forceWithLeaseArg(this.prBranch)] : [];
      return execGit(['push', '-u', ...forceArgs, 'fork', this.prBranch ?? ''], this.workingDir);
    }

    if (IS_INSTALLATION_TOKEN) {
      return this.createGithubVerifiedCommits();
    }

    if (this.forceUpdateBranch && this.prBranch) {
      return execGit(
        ['push', this.forceWithLeaseArg(this.prBranch), this.gitUrl, `HEAD:refs/heads/${this.prBranch}`],
        this.workingDir
      );
    }

    return execGit(['push', this.gitUrl], this.workingDir);
  }

  async findExistingPr(): Promise<PullRequestInfo | undefined> {
    const { data } = await this.github.pulls.list({
      owner: this.repo.user,
      repo: this.repo.name,
      state: 'open',
      head: `${FORK ? FORK : this.repo.user}:${this.prBranch}`
    });

    const pr = data[0];
    if (pr) {
      this.existingPr = {
        number: pr.number,
        html_url: pr.html_url,
        body: pr.body
      };
    }
    return this.existingPr;
  }

  async hasClosedPr(): Promise<boolean> {
    return (await this.getClosedPr()) !== undefined;
  }

  /**
   * Returns the most recent closed-but-unmerged PR for the current PR branch, or
   * undefined when none exists. Used to reopen a previously closed sync PR
   * instead of leaving it closed with an updated branch.
   */
  async getClosedPr(): Promise<PullRequestInfo | undefined> {
    const { data } = await this.github.pulls.list({
      owner: this.repo.user,
      repo: this.repo.name,
      state: 'closed',
      head: `${FORK ? FORK : this.repo.user}:${this.prBranch}`
    });

    // Only consider closed PRs that were NOT merged; pick the most recent one.
    const closed = data.filter((pr) => !pr.merged_at).sort((a, b) => b.number - a.number)[0];

    if (!closed) {
      return undefined;
    }

    return {
      number: closed.number,
      html_url: closed.html_url,
      body: closed.body
    };
  }

  /**
   * Returns true when the existing PR branch has fallen behind the base branch,
   * i.e. the base branch contains commits that are not yet in the PR branch.
   * Used by REBASE mode to decide whether to rebuild the PR branch on the latest
   * base. Uses the compare API so it works with shallow clones; on any error it
   * conservatively returns false (no force-update).
   */
  private async isBranchBehindBase(branch: string): Promise<boolean> {
    try {
      const { data } = await this.github.repos.compareCommits({
        owner: this.repo.user,
        repo: this.repo.name,
        base: FORK ? `${FORK}:${branch}` : branch,
        head: this.baseBranch
      });

      // `head` (the base branch) being ahead of `base` (the PR branch) means the
      // PR branch is missing base commits, so it is behind and should be rebased.
      return (data.ahead_by ?? 0) > 0;
    } catch (error) {
      core.debug(`Could not determine if ${branch} is behind ${this.baseBranch}: ${String(error)}`);
      return false;
    }
  }

  async deleteRemoteBranch(branch: string): Promise<void> {
    core.debug(`Deleting remote branch ${branch}`);
    try {
      await this.github.git.deleteRef({
        owner: this.repo.user,
        repo: this.repo.name,
        ref: `heads/${branch}`
      });
    } catch (error) {
      core.debug(`Failed to delete remote branch ${branch}: ${String(error)}`);
    }
  }

  async setPrWarning(): Promise<void> {
    if (!this.existingPr) return;

    await this.github.pulls.update({
      owner: this.repo.user,
      repo: this.repo.name,
      pull_number: this.existingPr.number,
      body: dedent`
        ⚠️ This PR is being automatically resynced (${new Date().toISOString()}) ⚠️

        ${this.existingPr.body ?? ''}
      `
    });
  }

  async removePrWarning(): Promise<void> {
    if (!this.existingPr) return;

    await this.github.pulls.update({
      owner: this.repo.user,
      repo: this.repo.name,
      pull_number: this.existingPr.number,
      body: (this.existingPr.body ?? '').replace(/⚠️ This PR is being automatically resynced \(.*?\) ⚠️/, '')
    });
  }

  /**
   * Gets all files changed in the existing pull request.
   * Returns a formatted HTML block listing every changed file in the PR branch.
   */
  private async getAllChangedFiles(): Promise<string> {
    if (!this.existingPr) return '';

    const files: string[] = [];
    let page = 1;

    while (true) {
      const { data } = await this.github.pulls.listFiles({
        owner: this.repo.user,
        repo: this.repo.name,
        pull_number: this.existingPr.number,
        per_page: 100,
        page
      });

      files.push(...data.map((file) => file.filename));

      if (data.length < 100) break;
      page += 1;
    }

    if (files.length === 0) return '';

    return dedent`
      <details>
      <summary>Changed files</summary>
      <ul>
      ${files.map((file) => `<li><code>${file}</code></li>`).join('\n')}
      </ul>
      </details>
    `;
  }

  async createOrUpdatePr(changedFiles: string, title?: string): Promise<PullRequestResult> {
    const branchSuffix = this.prBranchSuffix ? ` (${this.prBranchSuffix})` : '';
    const resolvedTitle = title ?? `${COMMIT_PREFIX} synced file(s) with ${GITHUB_REPOSITORY}${branchSuffix}`;

    // When updating an existing PR, recalculate all changed files from git diff
    const resolvedChangedFiles = this.existingPr ? await this.getAllChangedFiles() : changedFiles;

    const body = dedent`
      synced local file(s) with [${GITHUB_REPOSITORY}](${GITHUB_SERVER_URL}/${GITHUB_REPOSITORY}).

      ${PR_BODY}

      ${resolvedChangedFiles}

      ---

      This PR was created automatically by the [repo-files-sync-action](https://github.com/raven-actions/repo-files-sync) workflow run [#${
        process.env['GITHUB_RUN_ID'] || 0
      }](${GITHUB_SERVER_URL}/${GITHUB_REPOSITORY}/actions/runs/${process.env['GITHUB_RUN_ID'] || 0})
    `;

    if (this.existingPr) {
      core.info(this.prWasReopened ? `Updating reopened PR #${this.existingPr.number}` : 'Overwriting existing PR');

      const { data } = await this.github.pulls.update({
        owner: this.repo.user,
        repo: this.repo.name,
        title: resolvedTitle,
        pull_number: this.existingPr.number,
        body
      });

      const action: PrAction = this.prWasReopened ? 'reopened' : 'updated';
      this.existingPr = {
        number: data.number,
        html_url: data.html_url,
        body: data.body
      };
      this.prWasReopened = false;
      return { ...this.existingPr, action };
    }

    core.info('Creating new PR');

    const { data } = await this.github.pulls.create({
      owner: this.repo.user,
      repo: this.repo.name,
      title: resolvedTitle,
      body,
      head: `${FORK ? FORK : this.repo.user}:${this.prBranch}`,
      base: this.baseBranch
    });

    this.existingPr = {
      number: data.number,
      html_url: data.html_url,
      body: data.body
    };
    return { ...this.existingPr, action: 'created' };
  }

  async addPrLabels(labels: string[]): Promise<void> {
    if (!this.existingPr) return;

    await this.github.issues.addLabels({
      owner: this.repo.user,
      repo: this.repo.name,
      issue_number: this.existingPr.number,
      labels
    });
  }

  async addPrAssignees(assignees: string[]): Promise<void> {
    if (!this.existingPr) return;

    await this.github.issues.addAssignees({
      owner: this.repo.user,
      repo: this.repo.name,
      issue_number: this.existingPr.number,
      assignees
    });
  }

  async addPrReviewers(reviewers: string[]): Promise<void> {
    if (!this.existingPr) return;

    await this.github.pulls.requestReviewers({
      owner: this.repo.user,
      repo: this.repo.name,
      pull_number: this.existingPr.number,
      reviewers
    });
  }

  async addPrTeamReviewers(reviewers: string[]): Promise<void> {
    if (!this.existingPr) return;

    await this.github.pulls.requestReviewers({
      owner: this.repo.user,
      repo: this.repo.name,
      pull_number: this.existingPr.number,
      team_reviewers: reviewers
    });
  }

  async createGithubCommit(commitSha: string): Promise<void> {
    const [
      treeId,
      parentTreeId,
      commitMessage
    ] = await Promise.all([
      this.getTreeId(commitSha),
      this.getTreeId(`${commitSha}~1`),
      this.getCommitMessage(commitSha)
    ]);

    const treeDiff = await this.getTreeDiff(treeId, parentTreeId);

    core.debug('Uploading the blobs to GitHub');

    const blobsToCreate = treeDiff.filter(
      (e): e is TreeDiffEntry & { newBlob: string } => e.newMode !== '000000' && e.newBlob !== null
    );

    const pendingBlobs = [...blobsToCreate];
    const workers = Array.from({ length: Math.min(BLOB_UPLOAD_CONCURRENCY, pendingBlobs.length) }, async () => {
      let entry = pendingBlobs.shift();
      while (entry) {
        await this.uploadGitHubBlob(entry.newBlob);
        entry = pendingBlobs.shift();
      }
    });
    await Promise.all(workers);

    core.debug('Creating a GitHub tree');

    const tree: GitHubTreeEntry[] = treeDiff.map((e) => {
      let mode = e.newMode;
      let sha: string | null = e.newBlob;

      if (e.newMode === '000000') {
        // Set the sha to null to remove the file
        mode = e.previousMode;
        sha = null;
      }

      return {
        path: e.path,
        mode: mode as GitTreeMode,
        type: 'blob' as const,
        sha
      };
    });

    let treeSha: string;

    try {
      const request = await this.github.git.createTree({
        owner: this.repo.user,
        repo: this.repo.name,
        tree,
        base_tree: parentTreeId
      });
      treeSha = request.data.sha;
    } catch (error) {
      const err = error as Error;
      err.message = `Cannot create a new GitHub Tree: ${err.message}`;
      throw err;
    }

    core.debug('Creating a commit for the GitHub tree');

    const request = await this.github.git.createCommit({
      owner: this.repo.user,
      repo: this.repo.name,
      message: commitMessage,
      parents: [this.lastCommitSha],
      tree: treeSha
    });

    this.lastCommitSha = request.data.sha;
  }
}
